import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { UserProvider } from './context/UserContext';

// Импортируем тестовую страницу для проверки
const TestPage = () => (
  <div style={{ padding: '20px' }}>
    <h1>Тест</h1>
    <p>Если вы видите эту страницу, значит React-приложение работает!</p>
  </div>
);

function App() {
  return (
    <div className="app">
      <h1>Кошачья Империя</h1>
      <p>Тестовая страница</p>
    </div>
  );
}

export default App;
